// Alderyn - camada cliente do /jogar (A Gravura)
// Controla o DOM da pagina injetada pelo NiceGUI:
//   - chegada de texto (a luz que pousa no bloco novo) + SKIP + eco do jogador
//   - ritual de entrada (Adentrar) e Recomecar - via emitEvent pro Python
//   - HUD: por ora SO a Pressao Emocional (0-10). HP/Vigor/Mana/Fadiga e a
//     Tensao de combate (0-5) ficam como base pronta pro Degrau de combate.
//   - mixer (esqueleto p/ audio futuro via Howler - sem som por enquanto)
// Conversa com o Python via emitEvent (evento generico do NiceGUI).
//
// NOTA DE CANON: Pressao Emocional (0-10, ADR-003) e Tensao de combate
// (0-5, ADR-004) sao EIXOS SEPARADOS. setPressao mexe na Pressao; setTensao
// mexe na Tensao. Nunca um no lugar do outro.

type Vol = { master: number; amb: number; ev: number };

interface JogarAPI {
  init(): void;
  arrive(html: string, opts?: { fiador?: boolean; eco?: boolean }): void;
  skip(): void;
  entrar(): void;
  recomecar(): void;
  setPressao(n: number): void;
  setStat(nome: string, atual: number, max: number): void;
  setScene(texto: string): void;
  setTensao(n: number): void;
  mixer: {
    vols: Vol;
    muted: boolean;
    setVolume(bus: keyof Vol, v: number): void;
    setMuted(m: boolean): void;
  };
}

declare global {
  interface Window {
    Jogar: JogarAPI;
    emitEvent?: (name: string, ...args: unknown[]) => void;
  }
}

const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
let booted = false;
let revealing: HTMLElement | null = null;

const byId = (id: string) => document.getElementById(id);
const emit = (name: string, data: unknown) => { window.emitEvent?.(name, data); };

function bindInput(): boolean {
  const cmd = byId('cmd') as HTMLInputElement | null;
  if (!cmd) return false;
  const send = byId('send');
  const scrawl = byId('scrawl');
  const fire = () => {
    const text = cmd.value.trim();
    if (!text) return;
    emit('jogar_action', { text });
    cmd.value = '';
  };
  cmd.addEventListener('keydown', (e) => { if ((e as KeyboardEvent).key === 'Enter') fire(); });
  cmd.addEventListener('focus', () => scrawl?.classList.add('lit'));
  cmd.addEventListener('blur', () => scrawl?.classList.remove('lit'));
  send?.addEventListener('click', fire);

  // ritual de entrada + recomecar (botoes da propria Gravura)
  byId('adentrar')?.addEventListener('click', () => emit('jogar_comecar', {}));
  byId('recomecar')?.addEventListener('click', () => emit('jogar_recomecar', {}));
  return true;
}

const Jogar: JogarAPI = {
  init() {
    if (booted) return;
    if (!bindInput()) { window.setTimeout(() => Jogar.init(), 80); return; } // espera o NiceGUI injetar o HTML
    booted = true;
  },

  // chega um bloco. opts.fiador = voz do Fiador (italico, frio). opts.eco = a
  // acao que o jogador acabou de dizer (recuada, surda). Sem opts = prosa do Cronista.
  arrive(html, opts) {
    const corpo = byId('corpo');
    if (!corpo) return;
    // o bloco aceso vira "historia" (escurece) - a luz se move para o texto novo
    corpo.querySelectorAll('.glow:not(.faded)').forEach((el) => el.classList.add('faded'));
    const wrap = document.createElement('div');
    if (opts?.eco) {
      wrap.className = 'glow eco show';
      wrap.innerHTML = `<p class="eco-p">${html}</p>`;
    } else if (opts?.fiador) {
      wrap.className = 'glow show';
      wrap.innerHTML = `<div class="fiador"><svg width="20" height="20" viewBox="0 0 20 20" aria-hidden="true"><circle cx="10" cy="10" r="7.5" fill="none" stroke="#aeb6b8" stroke-width="1"/><line x1="4.7" y1="15.3" x2="15.3" y2="4.7" stroke="#aeb6b8" stroke-width="1"/></svg><p class="fline">${html}</p></div>`;
    } else {
      wrap.className = 'glow show';
      wrap.innerHTML = `<p>${html}</p>`;
    }
    corpo.appendChild(wrap);
    // a luz so "pousa" na prosa/fiador (mascara o TTFT). O eco e imediato, sem pulso.
    if (!reduce && !opts?.eco) wrap.classList.add('pulse');
    revealing = opts?.eco ? null : wrap;
    wrap.scrollIntoView({ behavior: reduce ? 'auto' : 'smooth', block: 'center' });
  },

  skip() {
    if (!revealing) return;
    revealing.classList.add('done');
    revealing.classList.remove('pulse');
    revealing = null;
  },

  // ritual: o portal de entrada sai de cena, a folha vira jogavel, foco no input.
  // o portal continua no DOM (so escondido) pra que Recomecar consiga traze-lo de volta.
  entrar() {
    const portal = byId('portal');
    portal?.classList.add('indo');
    window.setTimeout(() => portal?.classList.add('oculto'), 700);
    byId('scrawl')?.classList.remove('oculto');
    const cmd = byId('cmd') as HTMLInputElement | null;
    window.setTimeout(() => cmd?.focus(), 120);
  },

  // recomecar: apaga a narracao, devolve o portal, esconde o input - custo zero.
  recomecar() {
    const corpo = byId('corpo');
    corpo?.querySelectorAll('.glow').forEach((el) => el.remove());
    byId('scrawl')?.classList.add('oculto');
    const portal = byId('portal');
    portal?.classList.remove('oculto', 'indo');
    revealing = null;
  },

  // HUD ativo HOJE: a Pressao Emocional (0-10). A barra enche conforme sobe;
  // vira "sangue" no limite (>=7). Marginalia discreta - o numero nunca grita na prosa.
  setPressao(n) {
    const v = Math.max(0, Math.min(10, Math.round(n)));
    const fill = document.querySelector('#pressao .bar > i') as HTMLElement | null;
    if (fill) fill.style.width = (v * 10) + '%';
    const num = byId('pressao-num');
    if (num) num.textContent = `${v}`;
    byId('pressao')?.classList.toggle('alta', v >= 7);
  },

  // ---- base pronta pro Degrau de combate (ainda nao exibidos no HUD iii) ----
  setStat(nome, atual, max) {
    const el = document.querySelector(`[data-stat="${nome}"]`);
    if (!el) return;
    const bar = el.querySelector('.bar > i') as HTMLElement | null;
    const num = el.querySelector('.num') as HTMLElement | null;
    const pct = Math.max(0, Math.min(100, Math.round((atual / max) * 100)));
    if (bar) bar.style.width = pct + '%';
    if (num) num.textContent = `${atual}/${max}`;
  },

  setScene(texto) {
    const s = document.querySelector('.head .ttl');
    if (s) s.textContent = texto;
  },

  setTensao(n) {
    document.querySelectorAll('.lz').forEach((el, i) => el.classList.toggle('on', i < n));
  },

  mixer: {
    vols: { master: 0.7, amb: 0.7, ev: 0.7 },
    muted: false,
    setVolume(bus, v) { this.vols[bus] = v; /* TODO Howler: ganho quando houver audio CC0 real */ },
    setMuted(m) { this.muted = m; /* TODO Howler */ },
  },
};

window.Jogar = Jogar;
document.addEventListener('DOMContentLoaded', () => Jogar.init());
Jogar.init();
export {};
